import{_ as e,o as a,c as r,a2 as d}from"./chunks/framework.BZO4qERu.js";const c=JSON.parse('{"title":"騎砍2 | 新手求生指南：從被山賊追著跑到追著山賊跑","description":"","frontmatter":{},"headers":[],"relativePath":"bannerlord/beginner-guide.md","filePath":"bannerlord/beginner-guide.md"}'),l={name:"bannerlord/beginner-guide.md"};function n(o,t,i,s,h,g){return a(),r("div",null,[...t[0]||(t[0]=[d(`<h1 id="騎砍2-新手求生指南-從被山賊追著跑到追著山賊跑" tabindex="-1">騎砍2 | 新手求生指南：從被山賊追著跑到追著山賊跑 <a class="header-anchor" href="#騎砍2-新手求生指南-從被山賊追著跑到追著山賊跑" aria-label="Permalink to &quot;騎砍2 | 新手求生指南：從被山賊追著跑到追著山賊跑&quot;">​</a></h1><hr><h2 id="前言-你不是天選之人-你是個路人甲" tabindex="-1">前言：你不是天選之人，你是個路人甲 <a class="header-anchor" href="#前言-你不是天選之人-你是個路人甲" aria-label="Permalink to &quot;前言：你不是天選之人，你是個路人甲&quot;">​</a></h2><p>先說清楚一件事：騎砍2不是無雙遊戲。你剛進遊戲的時候，<strong>你就是個普通人</strong>。你連三個山賊都打不贏，你的馬跑得比別人的驢還慢，你的錢包比乞丐還空。</p><p>但這正是騎砍2好玩的地方——<strong>看著自己從被山賊追著滿地圖跑，變成帶著兩百精兵橫掃大陸，那種爽感是無可取代的。</strong></p><p>這篇指南就是幫你度過最痛苦的前期。</p><hr><h2 id="一、這遊戲到底在玩什麼" tabindex="-1">一、這遊戲到底在玩什麼？ <a class="header-anchor" href="#一、這遊戲到底在玩什麼" aria-label="Permalink to &quot;一、這遊戲到底在玩什麼？&quot;">​</a></h2><p>《騎馬與砍殺2：霸主》是一款中世紀沙盒角色扮演遊戲。你扮演一個無名冒險者，在卡拉迪亞大陸上從零開始。</p><p>核心循環一句話：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>打仗 → 賺錢 → 招更強的兵 → 打更大的仗 → 攻城 → 建國</span></span>
<span class="line"><span>  ↑_______________________________________________↓</span></span></code></pre></div><ul><li><strong>自由度極高：</strong> 你可以當傭兵、商人、封臣、國王，甚至純粹跑商一輩子</li><li><strong>沒有主線強迫你：</strong> 只有一個可選的龍旗任務，不做也能玩</li><li><strong>目標自己訂：</strong> 有人想統一全大陸，有人只想當個富商安享晚年</li></ul><hr><h2 id="二、角色創建-出身與屬性怎麼選" tabindex="-1">二、角色創建：出身與屬性怎麼選？ <a class="header-anchor" href="#二、角色創建-出身與屬性怎麼選" aria-label="Permalink to &quot;二、角色創建：出身與屬性怎麼選？&quot;">​</a></h2><h3 id="_2-1-文化選擇" tabindex="-1">2.1 文化選擇 <a class="header-anchor" href="#_2-1-文化選擇" aria-label="Permalink to &quot;2.1 文化選擇&quot;">​</a></h3><table tabindex="0"><thead><tr><th>文化</th><th>特色加成</th><th>一句話評價</th></tr></thead><tbody><tr><td><strong>帝國</strong></td><td>駐軍薪資-20%</td><td>什麼都會，最適合新手</td></tr><tr><td><strong>庫塞特</strong></td><td>騎兵地圖速度+10%</td><td>公認後期最強，騎射很噁心</td></tr><tr><td><strong>巴坦尼亞</strong></td><td>森林移動+10%</td><td>弓兵強到靠北，近戰是紙糊的</td></tr><tr><td><strong>瓦蘭迪亞</strong></td><td>戰鬥經驗+20%</td><td>騎兵衝鋒很爽，弩兵陣地戰無敵</td></tr><tr><td><strong>斯特吉亞</strong></td><td>雪地移動+10%</td><td>步兵硬得像坦克，移動像烏龜</td></tr><tr><td><strong>阿塞萊</strong></td><td>沙漠移動+10%、貿易懲罰-10%</td><td>騎兵便宜好用</td></tr></tbody></table><blockquote><p>🎯 <strong>新手推薦：帝國。</strong> 地理位置在地圖中央，兵種最均衡，駐軍減免讓你養兵壓力小。</p></blockquote><h3 id="_2-2-出身選擇" tabindex="-1">2.2 出身選擇 <a class="header-anchor" href="#_2-2-出身選擇" aria-label="Permalink to &quot;2.2 出身選擇&quot;">​</a></h3><p>創角時會被問幾個背景問題，影響起始屬性：</p><table tabindex="0"><thead><tr><th>出身</th><th style="text-align:center;">推薦度</th><th>原因</th></tr></thead><tbody><tr><td><strong>商人</strong></td><td style="text-align:center;">⭐⭐⭐</td><td>起始資金多、交易技能高</td></tr><tr><td>傭兵</td><td style="text-align:center;">⭐⭐</td><td>戰鬥技能好、起始裝備佳</td></tr><tr><td>貴族</td><td style="text-align:center;">⭐⭐</td><td>騎術和魅力高</td></tr></tbody></table><blockquote><p>🎯 <strong>新手推薦：商人出身。</strong> 起始資金2000金，有錢就能僱人幫你打。</p></blockquote><h3 id="_2-3-屬性點法" tabindex="-1">2.3 屬性點法 <a class="header-anchor" href="#_2-3-屬性點法" aria-label="Permalink to &quot;2.3 屬性點法&quot;">​</a></h3><table tabindex="0"><thead><tr><th>屬性</th><th style="text-align:center;">點數</th><th>原因</th></tr></thead><tbody><tr><td>活力</td><td style="text-align:center;">2</td><td>影響單手/雙手/長桿，戰鬥基礎</td></tr><tr><td>耐力</td><td style="text-align:center;">2</td><td>影響騎術和鍛造</td></tr><tr><td>社交</td><td style="text-align:center;">2</td><td>交易、魅力、領導力——決定你能帶多少兵、賺多少錢</td></tr><tr><td>智力</td><td style="text-align:center;">2</td><td>管理學影響帶兵上限</td></tr></tbody></table><blockquote><p>⚠️ 控制力（遠程）前期不用點。弓和弩前期傷害低，中期有裝備再回頭補。</p></blockquote><h3 id="_2-4-技能重點" tabindex="-1">2.4 技能重點 <a class="header-anchor" href="#_2-4-技能重點" aria-label="Permalink to &quot;2.4 技能重點&quot;">​</a></h3><ol><li><strong>單手+盾牌</strong>：容錯最高，新手首選</li><li><strong>騎術</strong>：點到能騎戰馬就夠（60）</li><li><strong>領導力</strong>：決定帶兵上限，必點</li><li><strong>交易</strong>：初期賺錢靠它</li><li><strong>鍛造</strong>：後期印鈔機，前期不急</li></ol><hr><h2 id="三、前五小時你該做什麼" tabindex="-1">三、前五小時你該做什麼？ <a class="header-anchor" href="#三、前五小時你該做什麼" aria-label="Permalink to &quot;三、前五小時你該做什麼？&quot;">​</a></h2><h3 id="_3-1-別急著打仗-先去競技場" tabindex="-1">3.1 別急著打仗，先去競技場 <a class="header-anchor" href="#_3-1-別急著打仗-先去競技場" aria-label="Permalink to &quot;3.1 別急著打仗，先去競技場&quot;">​</a></h3><p>每個城市都有競技場，進去打練習賽。<strong>這是前期最安全的練功方式</strong>：</p><ul><li>不會真的死掉（輸了只是昏倒）</li><li>可以練武器熟練度</li><li>贏了有獎金和裝備</li><li>帝國競技場裝備統一（單手劍+盾），最容易贏</li></ul><blockquote><p>💡 連續泡競技場幾輪，輕鬆賺到 3000-5000 金。</p></blockquote><h3 id="_3-2-接村莊任務賺第一桶金" tabindex="-1">3.2 接村莊任務賺第一桶金 <a class="header-anchor" href="#_3-2-接村莊任務賺第一桶金" aria-label="Permalink to &quot;3.2 接村莊任務賺第一桶金&quot;">​</a></h3><p>去各村莊找村長（站在村子裡的那個大叔），接任務：</p><table tabindex="0"><thead><tr><th>任務</th><th>報酬</th><th style="text-align:center;">難度</th></tr></thead><tbody><tr><td>送貨</td><td>300-800 金</td><td style="text-align:center;">簡單</td></tr><tr><td>找失蹤村民</td><td>200-500 金</td><td style="text-align:center;">簡單</td></tr><tr><td>打土匪</td><td>1000-3000 金</td><td style="text-align:center;">需要能打</td></tr></tbody></table><blockquote><p>送貨任務最穩，前期就是一直送貨、存錢。目標存到 5000 金。</p></blockquote><h3 id="_3-3-招兵買馬-但不要貪心" tabindex="-1">3.3 招兵買馬，但不要貪心 <a class="header-anchor" href="#_3-3-招兵買馬-但不要貪心" aria-label="Permalink to &quot;3.3 招兵買馬，但不要貪心&quot;">​</a></h3><p>有了錢第一件事：<strong>去村莊招兵</strong>。</p><p>新手常犯的錯誤是招太多兵養不起：</p><ul><li><strong>初期 15-20 人夠用了</strong></li><li>士兵的薪水是持續支出</li><li>帝國新兵 → 帝國步兵，這條線最穩定</li></ul><h3 id="_3-4-打山賊練等" tabindex="-1">3.4 打山賊練等 <a class="header-anchor" href="#_3-4-打山賊練等" aria-label="Permalink to &quot;3.4 打山賊練等&quot;">​</a></h3><p>當你有 15-20 個兵之後，開始找地圖上的劫匪（人數少於你的隊伍）。</p><p>打山賊的目的不是賺錢，是：</p><ol><li>練你自己的戰鬥技巧</li><li>練兵的等級</li><li>撿裝備賣錢</li><li>累積聲望（聲望 = 家族等級）</li></ol><hr><h2 id="四、雇傭兵-最被低估的戰略武器-🧠" tabindex="-1">四、雇傭兵：最被低估的戰略武器 🧠 <a class="header-anchor" href="#四、雇傭兵-最被低估的戰略武器-🧠" aria-label="Permalink to &quot;四、雇傭兵：最被低估的戰略武器 🧠&quot;">​</a></h2><p>很多人以為雇傭兵只是「過渡階段」，賺點錢就要趕快當封臣。大錯特錯！</p><p><strong>雇傭兵是整個遊戲最靈活的身分。</strong></p><h3 id="雇傭兵-vs-封臣-差在哪" tabindex="-1">雇傭兵 vs 封臣，差在哪？ <a class="header-anchor" href="#雇傭兵-vs-封臣-差在哪" aria-label="Permalink to &quot;雇傭兵 vs 封臣，差在哪？&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th>雇傭兵</th><th>封臣</th></tr></thead><tbody><tr><td>加入門檻</td><td>幾乎無</td><td>家族等級2+、國王同意</td></tr><tr><td>退出代價</td><td>零，隨時走人</td><td>扣關係、可能被追殺</td></tr><tr><td>敵對關係</td><td><strong>不會</strong>跟任何人變敵人</td><td>自動跟敵國所有人敵對</td></tr><tr><td>收入</td><td>日薪+戰利品</td><td>封地稅收+戰利品</td></tr><tr><td>機動性</td><td>今天打A國，明天幫A國打B國</td><td>綁定一國，不能隨便跳</td></tr></tbody></table><h3 id="核心戰略-用雇傭兵身分操控大陸局勢" tabindex="-1">核心戰略：用雇傭兵身分操控大陸局勢 <a class="header-anchor" href="#核心戰略-用雇傭兵身分操控大陸局勢" aria-label="Permalink to &quot;核心戰略：用雇傭兵身分操控大陸局勢&quot;">​</a></h3><p>這遊戲有一個隱藏機制：<strong>你幫誰打仗，誰就會變強；你打誰，誰就會變弱。</strong></p><p>而雇傭兵的身分，讓你可以自由操控這個天秤：</p><ol><li><strong>觀察地圖</strong>：打開百科全書（N鍵），看各國城池數量和兵力</li><li><strong>找出最強的國家</strong>：假設庫塞特已經吃掉半個帝國</li><li><strong>加入庫塞特的敵人</strong>：當阿塞萊的雇傭兵，專打庫塞特</li><li><strong>削弱庫塞特</strong>：抓他們領主、打他們軍團、圍他們的城</li><li><strong>見好就收</strong>：庫塞特變弱了 → 退出 → 看看下一家誰太強</li><li><strong>換邊再來</strong>：這次加入瓦蘭迪亞，去打另一個膨脹的國家</li></ol><blockquote><p>💡 <strong>一句話總結：當雇傭兵的終極目標不是賺錢，是確保卡拉迪亞沒有任何一國能獨大。</strong></p></blockquote><p>這樣等到你自立為王的時候，面對的是一個「各國互相制衡、誰都無法碾壓你」的大陸，而不是某個已經吃掉半張地圖的怪物。</p><hr><h2 id="五、這些坑千萬別踩-🕳️" tabindex="-1">五、這些坑千萬別踩 🕳️ <a class="header-anchor" href="#五、這些坑千萬別踩-🕳️" aria-label="Permalink to &quot;五、這些坑千萬別踩 🕳️&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">#</th><th>錯誤</th><th>後果</th><th>正確做法</th></tr></thead><tbody><tr><td style="text-align:center;">1</td><td>太早當封臣</td><td>被敵對國領主追著打、無法脫身</td><td>先當雇傭兵就好，封臣等家族等級3再說</td></tr><tr><td style="text-align:center;">2</td><td>太早攻城</td><td>全軍覆沒</td><td>沒有 100+ 精兵不要想攻城</td></tr><tr><td style="text-align:center;">3</td><td>錢全買裝備</td><td>沒錢養兵，兵跑光</td><td>永遠留至少養兵 7 天的薪水</td></tr><tr><td style="text-align:center;">4</td><td>無視俘虜系統</td><td>錯過穩定收入</td><td>俘虜賣給酒館贖金經紀人</td></tr><tr><td style="text-align:center;">5</td><td>忽視食物多樣性</td><td>士氣低 → 戰鬥力降</td><td>至少 3-4 種不同食物</td></tr><tr><td style="text-align:center;">6</td><td>同時跟多國開戰</td><td>被圍毆到亡國</td><td>一次只打一個敵人</td></tr></tbody></table><hr><h2 id="六、快速上手懶人包" tabindex="-1">六、快速上手懶人包 <a class="header-anchor" href="#六、快速上手懶人包" aria-label="Permalink to &quot;六、快速上手懶人包&quot;">​</a></h2><p>如果你是那種「字太多了」的人：</p><ol><li>創角：<strong>帝國 + 商人出身</strong></li><li>前 3 天：打競技場賺 5000 金 → 招 15 個帝國新兵</li><li>第 4-7 天：打劫匪練兵 + 接送貨任務</li><li>第 2 週：有 30 兵 + 10000 金 → 當雇傭兵，開始操控各國勢力平衡</li><li>之後：持續當雇傭兵牽制強國 → 存錢買工廠 → 等各國互相削弱後再自立</li></ol><hr><h2 id="📖-下一步" tabindex="-1">📖 下一步 <a class="header-anchor" href="#📖-下一步" aria-label="Permalink to &quot;📖 下一步&quot;">​</a></h2><ul><li>不知道招什麼兵？→ <a href="./troop-tier-list.html">騎砍2 | 兵種大亂鬥</a></li><li>錢不夠用？→ <a href="./money-making.html">騎砍2 | 賺錢密技</a></li><li>想自己當國王？→ <a href="./kingdom-building.html">騎砍2 | 自立為王</a></li></ul><hr><p><em>Blades Game 游刃攻略 — 遊刃有餘的遊戲攻略。全部原創內容，未經授權禁止轉載。</em></p><hr><h2 id="更新紀錄" tabindex="-1">更新紀錄 <a class="header-anchor" href="#更新紀錄" aria-label="Permalink to &quot;更新紀錄&quot;">​</a></h2><ul><li><strong>2026-06-11</strong>：文章建立。依據遊戲 v1.4.x 正式版撰寫。</li><li><strong>2026-06-11</strong>：新增「雇傭兵戰略」章節——補充雇傭兵 vs 封臣差異、用雇傭兵身分牽制各國勢力平衡的策略。</li></ul>`,71)])])}const _=e(l,[["render",n]]);export{c as __pageData,_ as default};
